6725         VectorTy->isVectorTy() ? ToVectorTy(SrcScalarTy, VF) : SrcScalarTy;
6726 
6727     if (canTruncateToMinimalBitwidth(I, VF)) {
6728       // If the result type is <= the source type, there will be no extend
6729       // after truncating the users to the minimal required bitwidth.
6730       if (VectorTy->getScalarSizeInBits() <= SrcVecTy->getScalarSizeInBits() &&
6731           (I->getOpcode() == Instruction::ZExt ||
6732            I->getOpcode() == Instruction::SExt))
6733         return 0;
6734     }
6735 
6736     return TTI.getCastInstrCost(Opcode, VectorTy, SrcVecTy, CCH, CostKind, I);
6737   }
6738   case Instruction::Call:
6739     return getVectorCallCost(cast<CallInst>(I), VF);
6740   case Instruction::ExtractValue:
6741     return TTI.getInstructionCost(I, TTI::TCK_RecipThroughput);
6742   case Instruction::Alloca:
6743     // We cannot easily widen alloca to a scalable alloca, as
6744     // the result would need to be a vector of pointers.
6745     if (VF.isScalable())
6746       return InstructionCost::getInvalid();
6747     [[fallthrough]];
6748   default:
6749     // This opcode is unknown. Assume that it is the same as 'mul'.
6750     return TTI.getArithmeticInstrCost(Instruction::Mul, VectorTy, CostKind);
6751   } // end of switch.
6752 }
